window.__SEPAKATEE_CATALOG_SEO__={"version":1,"by_id":{"146-surat-kuasa-berhutang":{"page_title":"Surat Kuasa Berhutang","meta_description":"Template surat kuasa berhutang Word (.docx) Sepakatee: kuasa khusus urusan piutang, pembayaran utang, dan administrasi terkait. Unduh legal setelah bayar.","keywords":"surat kuasa berhutang, kuasa hutang, template word, dokumen hukum, piutang","hero_subtitle":"Dokumen ini memuat pemberian kuasa kepada pihak lain untuk mewakili Anda dalam urusan yang berkaitan dengan hutang piutang—misalnya penagihan, perpanjangan jangka waktu, atau penandatanganan dokumen pendukung.","summary_intro":"Surat kuasa berhutang dipakai ketika Anda ingin seorang kuasa penerima bertindak atas nama pemberi kuasa dalam hal-hal yang terbatas pada hubungan utang piutang. Template ini membantu Anda menyusun identitas pihak, ruang lingkup kuasa, dan batas waktu dengan struktur yang rapi.","summary_points":["Cocok untuk individu maupun badan usaha yang perlu diwakili dalam administrasi pinjaman atau penagihan.","Ruang lingkup kuasa dapat disesuaikan dengan kebutuhan (hak khusus, tidak untuk mengalihkan kepemilikan harta kecuali dicantumkan).","Pastikan identitas pemberi dan penerima kuasa sesuai KTP/NPWP dan dokumen pendukung."]},"128-addendum-pengakuan-hutang":{"page_title":"Addendum Pengakuan Hutang","meta_description":"Addendum pengakuan hutang format Word Sepakatee: tambahan perjanjian untuk mengatur ulang jumlah, jadwal cicilan, atau syarat pelunasan. Siap edit setelah pembelian.","keywords":"addendum hutang, pengakuan hutang, perjanjian utang, template word","hero_subtitle":"Addendum ini melengkapi perjanjian atau pengakuan hutang yang sudah ada—misalnya mengubah nominal, bunga, jadwal bayar, atau jaminan—tanpa menandatangani kontrak baru dari nol.","summary_intro":"Addendum pengakuan hutang dipakai ketika para pihak sepakat mengubah sebagian ketentuan hutang piutang yang sudah diatur sebelumnya. Dokumen ini merujuk pada perjanjian induk dan menyatakan perubahan secara tegas agar mudah dibuktikan di kemudian hari.","summary_points":["Cantumkan referensi ke perjanjian/tanggal dokumen induk agar addendum terhubung jelas.","Jelaskan perubahan spesifik (plafon, tenor, denda, dsb.) untuk mengurangi sengketa interpretasi.","Disarankan ditandatangani oleh pihak yang sama yang berhak mengikat di perjanjian asli."]},"1-surat-perjanjian-sewa-menyewa-konter-hp":{"page_title":"Surat Perjanjian Sewa Menyewa Konter HP","meta_description":"Kontrak sewa konter HP format Word Sepakatee: durasi sewa, kewajiban penyewa, dan ketentuan penggunaan space ritel. Paket panduan penuh untuk pengisian terarah.","keywords":"sewa konter hp, perjanjian konter, kontrak ritel, template sewa menyewa","hero_subtitle":"Perjanjian sewa menyewa khusus untuk space konter ponsel/aksesoris—mengatur sewa, fasilitas bersama, jam operasional, dan kewajiban perawatan area dagang.","summary_intro":"Template ini membantu pemilik lokasi dan penyewa konter menyepakati hak dan kewajiban secara tertulis: mulai dari besaran sewa, deposit, larangan subsewa, hingga pengakhiran kontrak. Struktur mengikuti kebiasaan sewa menyewa komersial skala kecil.","summary_points":["Definisikan luasan/lokasi konter dan peralatan yang disediakan pemilik.","Atur kenaikan sewa berkala atau review kontrak agar transparan.","Sertakan ketentuan force majeure dan pengosongan jika salah satu pihak berhenti usaha."]},"82-akta-jual-beli-tanah-bersama-notaris":{"page_title":"Akta Jual Beli Tanah Bersama Notaris","meta_description":"Kerangka akta jual beli tanah bersama notaris Word Sepakatee. Referensi struktur pasal, identitas pihak, dan objek—sesuaikan dengan kantor notaris pilihan Anda.","keywords":"akta jual beli tanah, notaris, template akta, jual beli properti","hero_subtitle":"Dokumen terkait akta notaris membutuhkan penyesuaian dengan PPAT/notaris yang menangani. Template ini memberi kerangka isi umum: pihak, objek, harga, dan mekanisme balik nama.","summary_intro":"Akta jual beli tanah merupakan akta otentik yang biasanya dibuat di hadapan notaris/PPAT. File ini berfungsi sebagai draf kerja atau checklist isi sebelum Anda berkonsultasi dengan notaris resmi.","summary_points":["Lampirkan data sertifikat, NOP, dan status sengketa (jika ada) sebelum finalisasi.","Harga dan pajak pertambahan nilai/bea terkait mengikuti aturan yang berlaku saat transaksi.","Selalu validasi teks final bersama notaris yang berwenang di wilayah objek."]},"234-surat-perjanjian-jual-beli-tanah":{"page_title":"Surat Perjanjian Jual Beli Tanah","meta_description":"Surat perjanjian jual beli tanah format Word Sepakatee: uang muka, jadwal pelunasan, dan serah terima objek sebelum akta PPAT. Siap pakai tier dasar.","keywords":"perjanjian jual beli tanah, PPJB, template tanah, jual beli properti","hero_subtitle":"Perjanjian pra-akta yang mengatur harga, termin pembayaran, janji serah terima, dan sanksi wanprestasi sebelum dibuatkan akta resmi di notaris.","summary_intro":"Surat perjanjian jual beli tanah (sering dipakai sebagai PPJB) menjembatani kesepakatan awal antara penjual dan pembeli. Template ini membantu mencatat identitas bidang, bukti kepemilikan, dan mekanisme ganti rugi jika salah satu pihak mengundurkan diri.","summary_points":["Cantumkan nomor sertifikat, luas, dan batas bidang sesuai dokumen asli.","Atur mekanisme uang muka, pelunasan, dan biaya balik nama secara eksplisit.","Tambahkan pasal penyelesaian sengketa (musyawarah, arbitrase, atau pengadilan negeri)."]}}};
